import type { PublicCard } from '../../../types';

export const gcseRevisionCardsPart1: PublicCard[] = [
  // ── NUMBER (cards 1–40) ──────────────────────────────────────────────────
  { id: 'dc-gcse-revision-0001', deck_id: 'deck-gcse-revision', front: 'What is a prime number?', back: 'A prime number has exactly two factors: 1 and itself. Examples: 2, 3, 5, 7, 11, 13. Note: 1 is NOT prime. 2 is the only even prime.\n\nGCSE Tip: Learn primes up to 50 and be able to spot them in factor questions.', sort_order: 1 },
  { id: 'dc-gcse-revision-0002', deck_id: 'deck-gcse-revision', front: 'How do you find the HCF (Highest Common Factor) of two numbers?', back: 'Method 1 – List factors: write all factors of each number, pick the largest shared one.\nMethod 2 – Prime factorisation: write each as a product of primes, multiply the primes they share.\n\nExample: HCF(24, 36) → 24 = 2³×3, 36 = 2²×3² → shared: 2²×3 = 12\n\nGCSE Tip: Use Venn diagrams for prime factor trees — HCF is the intersection.', sort_order: 2 },
  { id: 'dc-gcse-revision-0003', deck_id: 'deck-gcse-revision', front: 'How do you find the LCM (Lowest Common Multiple) of two numbers?', back: 'Method – Prime factorisation: write each as a product of primes, multiply the highest power of each prime that appears.\n\nExample: LCM(12, 18) → 12 = 2²×3, 18 = 2×3² → LCM = 2²×3² = 36\n\nGCSE Tip: LCM is the union in the Venn diagram. Use HCF × LCM = product of two numbers as a check.', sort_order: 3 },
  { id: 'dc-gcse-revision-0004', deck_id: 'deck-gcse-revision', front: 'How do you write a number as a product of prime factors?', back: 'Use a prime factor tree or repeated division by primes.\n\nExample: 360 = 2 × 180 = 2 × 2 × 90 = 2 × 2 × 2 × 45 = 2 × 2 × 2 × 9 × 5 = 2³ × 3² × 5\n\nGCSE Tip: Always write the final answer in index form (using powers). The method is often worth marks even if you make an arithmetic slip.', sort_order: 4 },
  { id: 'dc-gcse-revision-0005', deck_id: 'deck-gcse-revision', front: 'What are the rules for multiplying and dividing fractions?', back: 'Multiply: multiply numerators together and denominators together. Simplify.\n  (3/4) × (2/5) = 6/20 = 3/10\n\nDivide: flip the second fraction then multiply.\n  (3/4) ÷ (2/5) = (3/4) × (5/2) = 15/8\n\nGCSE Tip: Never add or subtract denominators — only do that with addition/subtraction of fractions.', sort_order: 5 },
  { id: 'dc-gcse-revision-0006', deck_id: 'deck-gcse-revision', front: 'How do you add and subtract fractions with different denominators?', back: 'Find the LCM of the denominators (common denominator), convert each fraction, then add/subtract the numerators.\n\nExample: 2/3 + 3/4 → LCD = 12 → 8/12 + 9/12 = 17/12 = 1 5/12\n\nGCSE Tip: Always simplify your answer. Convert to a mixed number if the numerator > denominator.', sort_order: 6 },
  { id: 'dc-gcse-revision-0007', deck_id: 'deck-gcse-revision', front: 'How do you convert a fraction to a decimal and vice versa?', back: 'Fraction → decimal: divide numerator by denominator. E.g. 3/8 = 3 ÷ 8 = 0.375\n\nDecimal → fraction: write over the appropriate power of 10, then simplify.\n  0.36 = 36/100 = 9/25\n\nRecurring decimal → fraction: use algebra. E.g. 0.̄3 = 1/3; 0.̄1̄8̄ = 18/99 = 2/11\n\nGCSE Tip: Memorise common fractions: 1/3=0.333…, 1/4=0.25, 1/8=0.125, 1/5=0.2.', sort_order: 7 },
  { id: 'dc-gcse-revision-0008', deck_id: 'deck-gcse-revision', front: 'What is the method for converting a recurring decimal to a fraction?', back: 'Let x = the recurring decimal.\nMultiply x by a power of 10 to shift one full cycle, then subtract to cancel the recurring part.\n\nExample: x = 0.̄3̄6̄\n  100x = 36.363636…\n  99x = 36\n  x = 36/99 = 4/11\n\nGCSE Tip: The number of 9s in the denominator equals the number of recurring digits.', sort_order: 8 },
  { id: 'dc-gcse-revision-0009', deck_id: 'deck-gcse-revision', front: 'How do you calculate a percentage of an amount?', back: 'Multiply the amount by the percentage divided by 100.\n\nExample: 35% of £240 = (35/100) × 240 = 0.35 × 240 = £84\n\nFor non-calculator: break into 10% and 5%.\n  10% of 240 = 24; 5% = 12; 35% = 3×24 − 12 = 72 + 12 = 84\n\nGCSE Tip: Always show the multiplier method (×0.35) — it is the fastest and least error-prone.', sort_order: 9 },
  { id: 'dc-gcse-revision-0010', deck_id: 'deck-gcse-revision', front: 'How do you find the percentage change?', back: 'Percentage change = (change / original) × 100\n\nIncrease: change = new − original\nDecrease: change = original − new (result is negative if a decrease)\n\nExample: Price goes from £80 to £92 → change = 12 → % change = (12/80)×100 = 15% increase\n\nGCSE Tip: Always divide by the ORIGINAL value, not the new value.', sort_order: 10 },
  { id: 'dc-gcse-revision-0011', deck_id: 'deck-gcse-revision', front: 'How do you reverse a percentage (find the original amount)?', back: 'Identify the multiplier: if VAT (20%) is added, £120 = 1.20 × original.\nDivide by the multiplier: original = 120 ÷ 1.20 = £100\n\nFor a 15% reduction: sale price = 0.85 × original → original = sale price ÷ 0.85\n\nGCSE Tip: NEVER just work out a percentage of the final value — always divide by the multiplier.', sort_order: 11 },
  { id: 'dc-gcse-revision-0012', deck_id: 'deck-gcse-revision', front: 'What is compound interest and how do you calculate it?', back: 'Compound interest is interest earned on the interest already accumulated.\n\nFormula: A = P(1 + r/100)ⁿ\n  P = principal, r = annual rate (%), n = number of years\n\nExample: £500 at 3% for 4 years → A = 500 × (1.03)⁴ = 500 × 1.1255 ≈ £562.75\n\nGCSE Tip: Distinguish from simple interest (I = PRT/100). Use the multiplier method — don\'t calculate interest year by year.', sort_order: 12 },
  { id: 'dc-gcse-revision-0013', deck_id: 'deck-gcse-revision', front: 'What is a surd and how do you simplify one?', back: 'A surd is an irrational square root that cannot be simplified to a whole number or fraction. E.g. √2, √5, √12.\n\nSimplify by finding the largest perfect square factor:\n  √72 = √(36×2) = 6√2\n  √75 = √(25×3) = 5√3\n\nGCSE Tip: Look for perfect square factors: 4, 9, 16, 25, 36, 49, 64… Always fully simplify.', sort_order: 13 },
  { id: 'dc-gcse-revision-0014', deck_id: 'deck-gcse-revision', front: 'How do you multiply and divide surds?', back: '√a × √b = √(ab)         e.g. √3 × √5 = √15\n√a × √a = a              e.g. √7 × √7 = 7\n√a ÷ √b = √(a/b)         e.g. √20 ÷ √5 = √4 = 2\n\nAlso: k√a × m√b = km√(ab)\n  3√2 × 4√3 = 12√6\n\nGCSE Tip: Keep answers in surd form unless asked for a decimal.', sort_order: 14 },
  { id: 'dc-gcse-revision-0015', deck_id: 'deck-gcse-revision', front: 'How do you rationalise a denominator of the form 1/√a?', back: 'Multiply numerator and denominator by √a:\n  1/√5 = (1×√5)/(√5×√5) = √5/5\n\nFor 1/(a + √b), multiply by (a − √b)/(a − √b) — the conjugate:\n  1/(2 + √3) × (2−√3)/(2−√3) = (2−√3)/(4−3) = 2−√3\n\nGCSE Tip: "Rationalise the denominator" means remove the surd from the bottom of the fraction.', sort_order: 15 },
  { id: 'dc-gcse-revision-0016', deck_id: 'deck-gcse-revision', front: 'What is standard form (scientific notation)?', back: 'Standard form: A × 10ⁿ where 1 ≤ A < 10 and n is an integer.\n\nExamples:\n  4,500,000 = 4.5 × 10⁶\n  0.000032 = 3.2 × 10⁻⁵\n\nTo multiply: multiply the A values, add the powers of 10.\n  (3×10⁴) × (2×10³) = 6×10⁷\n\nGCSE Tip: Move the decimal point: right = positive power, left = negative power.', sort_order: 16 },
  { id: 'dc-gcse-revision-0017', deck_id: 'deck-gcse-revision', front: 'What are the index laws (laws of exponents)?', back: 'aᵐ × aⁿ = aᵐ⁺ⁿ      (multiply → add powers)\naᵐ ÷ aⁿ = aᵐ⁻ⁿ      (divide → subtract powers)\n(aᵐ)ⁿ = aᵐⁿ          (power of a power → multiply)\na⁰ = 1               (any base to power 0)\na⁻ⁿ = 1/aⁿ          (negative power → reciprocal)\naˡ/ⁿ = ⁿ√a           (fraction power → nth root)\naᵐ/ⁿ = (ⁿ√a)ᵐ       (root then power)\n\nGCSE Tip: 27^(2/3) = (∛27)² = 3² = 9. Root first, then power — easier numbers.', sort_order: 17 },
  { id: 'dc-gcse-revision-0018', deck_id: 'deck-gcse-revision', front: 'How do you round to significant figures (s.f.)?', back: 'Count from the first non-zero digit.\n  1st s.f. of 0.00462 is the 4.\n  Rounded to 2 s.f.: 0.0046\n\n  4,832 to 3 s.f. = 4,830\n\nRule: look at the next digit — if 5 or more, round up.\n\nGCSE Tip: Standard form questions often ask for answers to 3 s.f. "Significant" means meaningful — leading zeros are NOT significant.', sort_order: 18 },
  { id: 'dc-gcse-revision-0019', deck_id: 'deck-gcse-revision', front: 'What is the difference between upper and lower bounds?', back: 'When a measurement is given to a degree of accuracy, the true value lies in a range:\n  lower bound = stated value − half the unit of accuracy\n  upper bound = stated value + half the unit of accuracy\n\nExample: 7.4 cm (to 1 d.p.) → LB = 7.35 cm, UB = 7.45 cm\n\nGCSE Tip: Upper bound is < 7.45 (not ≤). For error interval notation: 7.35 ≤ x < 7.45.', sort_order: 19 },
  { id: 'dc-gcse-revision-0020', deck_id: 'deck-gcse-revision', front: 'How do you calculate with bounds (e.g. maximum/minimum of a calculation)?', back: 'To maximise a result:\n  • Addition/multiplication → use upper bounds\n  • Division (a÷b) → use max a and min b (UB ÷ LB)\n\nTo minimise a result:\n  • Use lower bounds (LB ÷ UB for division)\n\nExample: a = 4.5 (±0.05), b = 2.3 (±0.05)\n  Max a/b = 4.55/2.25 ≈ 2.022…\n\nGCSE Tip: Always state which bounds you are using in your working.', sort_order: 20 },
  { id: 'dc-gcse-revision-0021', deck_id: 'deck-gcse-revision', front: 'How do you estimate the answer to a calculation?', back: 'Round every value to 1 significant figure, then calculate.\n\nExample: (38.2 × 4.91) / 0.52 ≈ (40 × 5) / 0.5 = 200 / 0.5 = 400\n\nGCSE Tip: Show clearly that you have rounded (use ≈). You may get method marks even if the final estimate differs slightly from the mark scheme value.', sort_order: 21 },
  { id: 'dc-gcse-revision-0022', deck_id: 'deck-gcse-revision', front: 'What is the order of operations (BIDMAS/BODMAS)?', back: 'Brackets → Indices (powers/roots) → Division → Multiplication → Addition → Subtraction\n\nExample: 3 + 4² ÷ (2 × 4) − 1\n  = 3 + 16 ÷ 8 − 1\n  = 3 + 2 − 1 = 4\n\nGCSE Tip: Division and multiplication have equal priority (left to right), as do addition and subtraction. Don\'t just go left to right — respect the hierarchy.', sort_order: 22 },
  { id: 'dc-gcse-revision-0023', deck_id: 'deck-gcse-revision', front: 'How do you work out a fraction of a quantity?', back: 'Divide by the denominator, then multiply by the numerator.\n\nExample: 3/7 of 280 = (280 ÷ 7) × 3 = 40 × 3 = 120\n\nGCSE Tip: "Of" means multiply. You can also write it as (3/7) × 280 = 840/7 = 120. Both methods score full marks.', sort_order: 23 },
  { id: 'dc-gcse-revision-0024', deck_id: 'deck-gcse-revision', front: 'What is a rational number vs an irrational number?', back: 'Rational: can be written as a fraction p/q where p and q are integers and q ≠ 0.\n  Includes: whole numbers, fractions, terminating and recurring decimals.\n\nIrrational: cannot be expressed as a fraction.\n  Includes: √2, √3, π, e\n\nGCSE Tip: √4 = 2 IS rational. √9 = 3 IS rational. Only non-perfect-square roots are irrational.', sort_order: 24 },
  { id: 'dc-gcse-revision-0025', deck_id: 'deck-gcse-revision', front: 'How do you solve problems involving negative numbers?', back: 'Addition/subtraction:\n  −3 + (−5) = −8;   −3 − (−5) = −3 + 5 = 2\n\nMultiplication/division:\n  (+) × (+) = (+);   (−) × (−) = (+)\n  (+) × (−) = (−);   (−) × (+) = (−)\n\nGCSE Tip: Two negatives multiplied/divided always give a positive. Be careful with directed number arithmetic in substitution questions.', sort_order: 25 },
  { id: 'dc-gcse-revision-0026', deck_id: 'deck-gcse-revision', front: 'What is a factor, a multiple, and a square number?', back: 'Factor: a number that divides exactly into another. Factors of 12: 1, 2, 3, 4, 6, 12.\n\nMultiple: the result of multiplying a number by a positive integer. Multiples of 7: 7, 14, 21, 28…\n\nSquare number: an integer × itself. 1, 4, 9, 16, 25, 36, 49, 64, 81, 100…\n\nGCSE Tip: Know the first 15 square numbers and 12 cube numbers by heart.', sort_order: 26 },
  { id: 'dc-gcse-revision-0027', deck_id: 'deck-gcse-revision', front: 'What is a cube number and a cube root?', back: 'Cube numbers: 1³=1, 2³=8, 3³=27, 4³=64, 5³=125, 6³=216, 7³=343, 8³=512, 9³=729, 10³=1000.\n\nCube root ∛: the inverse of cubing.\n  ∛125 = 5 because 5³ = 125\n  ∛(−8) = −2 (cube roots of negatives are defined)\n\nGCSE Tip: Unlike square roots, cube roots can be negative.', sort_order: 27 },
  { id: 'dc-gcse-revision-0028', deck_id: 'deck-gcse-revision', front: 'How do you simplify a ratio and share an amount in a given ratio?', back: 'Simplify: divide both parts by their HCF.\n  18:24 → HCF = 6 → 3:4\n\nShare £350 in ratio 3:4:\n  Total parts = 7\n  1 part = 350 ÷ 7 = 50\n  Shares: 3×50 = £150 and 4×50 = £200\n\nGCSE Tip: Always state what one part is worth before calculating shares — it avoids errors.', sort_order: 28 },
  { id: 'dc-gcse-revision-0029', deck_id: 'deck-gcse-revision', front: 'How do you express one quantity as a percentage of another?', back: 'Divide the part by the whole, then multiply by 100.\n\nExample: 18 out of 24 → (18/24) × 100 = 75%\n\nGCSE Tip: Make sure both quantities are in the same units before dividing. "Express A as a percentage of B" always means (A/B) × 100.', sort_order: 29 },
  { id: 'dc-gcse-revision-0030', deck_id: 'deck-gcse-revision', front: 'What is direct and inverse proportion?', back: 'Direct: y ∝ x means y = kx (as x doubles, y doubles).\n  k = y/x is constant.\n\nInverse: y ∝ 1/x means y = k/x (as x doubles, y halves).\n  k = xy is constant.\n\nGCSE Tip: Graph of direct proportion is a straight line through origin. Inverse proportion is a hyperbola (curved). Always find k first.', sort_order: 30 },
  { id: 'dc-gcse-revision-0031', deck_id: 'deck-gcse-revision', front: 'How do you calculate with speed, distance, and time?', back: 'Triangle: Distance = Speed × Time\n  Speed = Distance ÷ Time\n  Time = Distance ÷ Speed\n\nUnits must match: if speed is km/h, distance in km, time in hours.\n\nExample: Car travels 150 km at 60 km/h → Time = 150/60 = 2.5 hours = 2 h 30 min\n\nGCSE Tip: Convert minutes to hours (÷60) before using the formula.', sort_order: 31 },
  { id: 'dc-gcse-revision-0032', deck_id: 'deck-gcse-revision', front: 'What is density and how do you calculate it?', back: 'Density = Mass ÷ Volume\n  Mass = Density × Volume\n  Volume = Mass ÷ Density\n\nUnits: g/cm³ or kg/m³\n\nExample: A block has mass 240 g and volume 30 cm³ → Density = 240/30 = 8 g/cm³\n\nGCSE Tip: Use the triangle (same as speed/distance/time). Pay attention to units — the question may give g and m³ requiring conversion.', sort_order: 32 },
  { id: 'dc-gcse-revision-0033', deck_id: 'deck-gcse-revision', front: 'How do you solve problems using the unitary method?', back: 'Find the value of one unit, then scale up or down.\n\nExample: 5 pens cost £3.50. Cost of 8 pens?\n  1 pen = £3.50 ÷ 5 = £0.70\n  8 pens = 8 × £0.70 = £5.60\n\nGCSE Tip: The unitary method also applies to exchange rates, recipes, and best-buy comparisons. Always find "1 unit" first.', sort_order: 33 },
  { id: 'dc-gcse-revision-0034', deck_id: 'deck-gcse-revision', front: 'How do you calculate with money: profit, loss, and VAT?', back: 'Profit = selling price − cost price\nLoss = cost price − selling price\nProfit % = (profit / cost price) × 100\n\nVAT at 20%: add 20% → multiply by 1.20\n  Pre-VAT price: divide by 1.20\n\nExample: Cost £40, sold £52 → Profit = £12 → Profit% = (12/40)×100 = 30%\n\nGCSE Tip: Profit and loss percentages are always out of the COST PRICE, not the selling price.', sort_order: 34 },
  { id: 'dc-gcse-revision-0035', deck_id: 'deck-gcse-revision', front: 'What does it mean for a number to be written in index form?', back: 'Index form (or exponential form) writes a number as a base raised to a power.\n  8 = 2³ (base 2, index/power 3)\n  100 = 10²\n\nPrime factor index form: 360 = 2³ × 3² × 5\n\nGCSE Tip: Questions often ask you to "write as a product of prime factors" — that means fully decompose into primes in index form.', sort_order: 35 },
  { id: 'dc-gcse-revision-0036', deck_id: 'deck-gcse-revision', front: 'What is simple interest?', back: 'Simple interest: I = PRT/100\n  P = principal (original amount)\n  R = annual rate (%)\n  T = time (years)\n\nExample: £800 at 4% for 3 years → I = (800×4×3)/100 = £96\n\nGCSE Tip: Unlike compound interest, simple interest is calculated on the original amount each year — the interest does not itself earn interest.', sort_order: 36 },
  { id: 'dc-gcse-revision-0037', deck_id: 'deck-gcse-revision', front: 'How do you interpret and use number lines for inequalities?', back: 'Closed circle ● means the end value IS included (≤ or ≥).\nOpen circle ○ means the end value is NOT included (< or >).\n\nExample: −2 < x ≤ 4 → open circle at −2, closed circle at 4, line between them.\n\nInteger solutions of −2 < x ≤ 4: {−1, 0, 1, 2, 3, 4}\n\nGCSE Tip: Write out integer solutions when asked — include both end integers where appropriate.', sort_order: 37 },
  { id: 'dc-gcse-revision-0038', deck_id: 'deck-gcse-revision', front: 'How do you calculate with powers and roots on a calculator?', back: 'Square root: √ button. Cube root: ∛ or xⁿ with n = 1/3.\nPowers: use xⁿ or ^ key.\n\nExample: 2.5³ = 2.5 ^ 3 = 15.625\n  ∛64 = 64^(1/3) = 4\n\nFor fraction powers: (27)^(2/3) = (∛27)² = 9. Enter: 27^(2÷3) on calculator.\n\nGCSE Tip: Use brackets around the fraction power to avoid calculator misinterpretation.', sort_order: 38 },
  { id: 'dc-gcse-revision-0039', deck_id: 'deck-gcse-revision', front: 'What is a truncated number and how does it differ from rounding?', back: 'Truncation: simply remove the unwanted digits without rounding.\n  3.769 truncated to 2 d.p. = 3.76 (NOT rounded to 3.77)\n\nRounding: look at the next digit — round up if 5 or more.\n  3.769 rounded to 2 d.p. = 3.77\n\nGCSE Tip: Truncation always gives a result ≤ the actual value. Used in calculator displays and error intervals.', sort_order: 39 },
  { id: 'dc-gcse-revision-0040', deck_id: 'deck-gcse-revision', front: 'How do you use a Venn diagram for HCF and LCM?', back: 'Draw two overlapping circles, one for each number.\n\nPlace prime factors:\n  • Shared factors go in the overlap\n  • Remaining factors go in their own circle\n\nHCF = product of numbers in the overlap\nLCM = product of ALL numbers in both circles\n\nExample: 12 = 2²×3, 18 = 2×3²\n  Overlap: 2×3; Left only: 2; Right only: 3\n  HCF = 2×3 = 6; LCM = 2×2×3×3 = 36\n\nGCSE Tip: This method is often asked explicitly in exams.', sort_order: 40 },

  // ── ALGEBRA (cards 41–95) ────────────────────────────────────────────────
  { id: 'dc-gcse-revision-0041', deck_id: 'deck-gcse-revision', front: 'How do you expand a single bracket?', back: 'Multiply every term inside the bracket by the term outside.\n\n3x(2x − 5) = 6x² − 15x\n−2(3a + 4b) = −6a − 8b\n\nGCSE Tip: Pay careful attention to negative signs outside the bracket — each term inside changes sign.', sort_order: 41 },
  { id: 'dc-gcse-revision-0042', deck_id: 'deck-gcse-revision', front: 'How do you expand double brackets (FOIL)?', back: 'Multiply each term in the first bracket by each term in the second.\n(First)(Last)(Outer)(Inner) — FOIL:\n\n(x + 3)(x + 5) = x² + 5x + 3x + 15 = x² + 8x + 15\n(2x − 1)(3x + 4) = 6x² + 8x − 3x − 4 = 6x² + 5x − 4\n\nGCSE Tip: Always collect like terms after expanding. Show four separate products before simplifying.', sort_order: 42 },
  { id: 'dc-gcse-revision-0043', deck_id: 'deck-gcse-revision', front: 'How do you expand (a + b)² and (a − b)²?', back: '(a + b)² = a² + 2ab + b²\n(a − b)² = a² − 2ab + b²\n(a + b)(a − b) = a² − b²  ← difference of two squares\n\nExample:\n(3x + 2)² = 9x² + 12x + 4\n(5 − x)(5 + x) = 25 − x²\n\nGCSE Tip: Memorise these identities — they appear very frequently and save time.', sort_order: 43 },
  { id: 'dc-gcse-revision-0044', deck_id: 'deck-gcse-revision', front: 'How do you factorise simple expressions?', back: 'Find the highest common factor (HCF) of all terms, place it outside the bracket.\n\nExamples:\n  6x² + 9x = 3x(2x + 3)\n  15a²b − 10ab² = 5ab(3a − 2b)\n\nCheck: expand to verify.\n\nGCSE Tip: Always look for a common factor FIRST before attempting other factorisations. The HCF includes numbers and variables.', sort_order: 44 },
  { id: 'dc-gcse-revision-0045', deck_id: 'deck-gcse-revision', front: 'How do you factorise a quadratic of the form x² + bx + c?', back: 'Find two numbers that multiply to c and add to b:\n  x² + 7x + 12 → need ×12, +7 → 3 and 4 → (x+3)(x+4)\n\nIf c is negative, one number is negative:\n  x² + 2x − 15 → ×(−15), +2 → 5 and −3 → (x+5)(x−3)\n\nGCSE Tip: Set each factor equal to zero to find the roots. Check by expanding.', sort_order: 45 },
  { id: 'dc-gcse-revision-0046', deck_id: 'deck-gcse-revision', front: 'How do you factorise a quadratic of the form ax² + bx + c?', back: 'Method: multiply a × c, find two numbers that give that product and sum to b, split the middle term, factor by grouping.\n\nExample: 2x² + 7x + 3\n  a×c = 6; need ×6, +7 → 1 and 6\n  2x² + x + 6x + 3 = x(2x+1) + 3(2x+1) = (x+3)(2x+1)\n\nGCSE Tip: Always check if there is a common factor first to simplify before applying this method.', sort_order: 46 },
  { id: 'dc-gcse-revision-0047', deck_id: 'deck-gcse-revision', front: 'How do you solve a linear equation?', back: 'Goal: isolate the unknown on one side.\n  • Add/subtract the same to both sides\n  • Multiply/divide both sides by the same (non-zero) value\n\nExample: 3x − 7 = 14\n  3x = 21\n  x = 7\n\nWith fractions: 2x/3 + 1 = 5 → 2x/3 = 4 → 2x = 12 → x = 6\n\nGCSE Tip: Show every step. Collect xs on the side where they are positive.', sort_order: 47 },
  { id: 'dc-gcse-revision-0048', deck_id: 'deck-gcse-revision', front: 'How do you solve equations with brackets?', back: 'Expand the brackets first, then solve as a linear equation.\n\nExample: 4(2x − 3) = 2(x + 5)\n  8x − 12 = 2x + 10\n  6x = 22\n  x = 22/6 = 11/3\n\nGCSE Tip: Leave the answer as a fraction unless told otherwise. Always check by substituting back.', sort_order: 48 },
  { id: 'dc-gcse-revision-0049', deck_id: 'deck-gcse-revision', front: 'How do you solve a quadratic equation by factorising?', back: 'Rearrange so one side = 0, then factorise, then set each factor = 0.\n\nExample: x² + 5x − 14 = 0\n  (x + 7)(x − 2) = 0\n  x = −7  or  x = 2\n\nGCSE Tip: Always rearrange to = 0 first. A quadratic can have 0, 1, or 2 solutions.', sort_order: 49 },
  { id: 'dc-gcse-revision-0050', deck_id: 'deck-gcse-revision', front: 'How do you use the quadratic formula?', back: 'For ax² + bx + c = 0:\n  x = [−b ± √(b² − 4ac)] / 2a\n\nExample: 3x² − 5x − 2 = 0\n  a=3, b=−5, c=−2\n  x = [5 ± √(25+24)] / 6 = [5 ± 7] / 6\n  x = 2  or  x = −1/3\n\nGCSE Tip: If b² − 4ac < 0 there are no real solutions. Leave answer to 2 d.p. if asked.', sort_order: 50 },
  { id: 'dc-gcse-revision-0051', deck_id: 'deck-gcse-revision', front: 'How do you complete the square to solve a quadratic?', back: 'For x² + bx + c = 0:\n  (x + b/2)² − (b/2)² + c = 0\n  (x + b/2)² = (b/2)² − c\n  x = −b/2 ± √[(b/2)² − c]\n\nExample: x² + 6x + 7 = 0\n  (x+3)² − 9 + 7 = 0 → (x+3)² = 2\n  x = −3 ± √2\n\nGCSE Tip: Completing the square also reveals the vertex of a parabola (minimum/maximum).', sort_order: 51 },
  { id: 'dc-gcse-revision-0052', deck_id: 'deck-gcse-revision', front: 'How do you solve linear inequalities?', back: 'Solve like an equation — BUT reverse the inequality sign when multiplying or dividing by a negative.\n\nExample: 3 − 2x > 7\n  −2x > 4\n  x < −2 (sign reverses when ÷ by −2)\n\nGCSE Tip: Show the solution on a number line. Use integer values: for x < −2, integers are …, −5, −4, −3. Check by substituting a value.', sort_order: 52 },
  { id: 'dc-gcse-revision-0053', deck_id: 'deck-gcse-revision', front: 'What is the gradient-intercept form of a straight line?', back: 'y = mx + c\n  m = gradient (steepness), c = y-intercept (where line cuts y-axis)\n\nExample: y = 3x − 2 → gradient 3, y-intercept −2.\n\nTo find m from two points: m = (y₂−y₁)/(x₂−x₁)\n\nGCSE Tip: Rearrange to y = mx + c before reading off gradient/intercept.', sort_order: 53 },
  { id: 'dc-gcse-revision-0054', deck_id: 'deck-gcse-revision', front: 'How do you find the equation of a line given gradient and point?', back: 'Use: y − y₁ = m(x − x₁), where (x₁, y₁) is the known point.\n\nExample: m = 2, passes through (3, 5)\n  y − 5 = 2(x − 3)\n  y = 2x − 1\n\nAlternatively: substitute into y = mx + c to find c.\n  5 = 2(3) + c → c = −1 → y = 2x − 1\n\nGCSE Tip: Both methods are valid. Rearrange to y = mx + c as your final form.', sort_order: 54 },
  { id: 'dc-gcse-revision-0055', deck_id: 'deck-gcse-revision', front: 'What is the relationship between gradients of parallel and perpendicular lines?', back: 'Parallel lines: same gradient (m₁ = m₂)\n\nPerpendicular lines: gradients multiply to −1\n  m₂ = −1/m₁ (negative reciprocal)\n\nExample: y = 3x + 1 is perpendicular to y = −(1/3)x + 4\n\nGCSE Tip: Always check: is the question asking for parallel (same m) or perpendicular (flip and negate m)?', sort_order: 55 },
  { id: 'dc-gcse-revision-0056', deck_id: 'deck-gcse-revision', front: 'How do you solve simultaneous linear equations by elimination?', back: 'Make coefficients of one variable equal (multiply equations if needed), then add or subtract to eliminate it.\n\nExample:\n  2x + 3y = 11 …(1)\n  4x − y = 9  …(2)\nMultiply (2) by 3: 12x − 3y = 27\nAdd to (1): 14x = 38 → x = 38/14 = 19/7 … or use simpler numbers.\n\nSimpler: 3x + y = 7 and x + y = 3 → subtract → 2x = 4 → x=2, y=1\n\nGCSE Tip: Label equations and show the operation clearly for method marks.', sort_order: 56 },
  { id: 'dc-gcse-revision-0057', deck_id: 'deck-gcse-revision', front: 'How do you solve simultaneous equations by substitution?', back: 'Rearrange one equation to express one variable, substitute into the other.\n\nExample:\n  y = 2x − 1 …(1)\n  3x + 2y = 12 …(2)\n  Sub (1) into (2): 3x + 2(2x−1) = 12 → 7x − 2 = 12 → x = 2, y = 3\n\nGCSE Tip: Substitution is essential when one equation is non-linear (e.g. a circle). Always check both values in BOTH original equations.', sort_order: 57 },
  { id: 'dc-gcse-revision-0058', deck_id: 'deck-gcse-revision', front: 'How do you solve one linear and one quadratic simultaneously?', back: 'From the linear equation, express y in terms of x (or x in terms of y), substitute into the quadratic, then solve.\n\nExample:\n  y = x + 3  and  x² + y² = 29\n  x² + (x+3)² = 29\n  x² + x² + 6x + 9 = 29\n  2x² + 6x − 20 = 0 → x² + 3x − 10 = 0\n  (x+5)(x−2) = 0 → x = −5 or 2; y = −2 or 5\n\nGCSE Tip: Always substitute back to get corresponding y-values. There are usually two solution pairs.', sort_order: 58 },
  { id: 'dc-gcse-revision-0059', deck_id: 'deck-gcse-revision', front: 'What is an arithmetic sequence and how do you find the nth term?', back: 'An arithmetic sequence has a constant difference d between terms.\n  nth term = a + (n−1)d = dn + (a − d)\n  where a = first term, d = common difference.\n\nExample: 5, 8, 11, 14, … → a=5, d=3 → nth term = 3n + 2\n\nGCSE Tip: To find d: subtract any term from the next. Substitute n=1 to verify.', sort_order: 59 },
  { id: 'dc-gcse-revision-0060', deck_id: 'deck-gcse-revision', front: 'What is a geometric sequence and how do you identify it?', back: 'A geometric sequence has a constant ratio r between consecutive terms.\n  Tₙ = arⁿ⁻¹ where a = first term, r = common ratio.\n\nExample: 3, 6, 12, 24, 48, … → r = 2 → Tₙ = 3 × 2ⁿ⁻¹\n\nIdentify: divide any term by the previous term — if ratio is constant, it is geometric.\n\nGCSE Tip: Check sign of r. If r is negative, the sequence alternates in sign.', sort_order: 60 },
  { id: 'dc-gcse-revision-0061', deck_id: 'deck-gcse-revision', front: 'How do you substitute values into a formula?', back: 'Replace each letter with its numerical value, following BIDMAS.\n\nExample: v = u + at; find v when u=5, a=3, t=4\n  v = 5 + 3×4 = 5 + 12 = 17\n\nExample: E = mc²; find E when m=2, c=3×10⁸\n  E = 2 × (3×10⁸)² = 2 × 9×10¹⁶ = 1.8×10¹⁷\n\nGCSE Tip: Write each substituted line clearly — marks are awarded for correct substitution even if the arithmetic goes wrong.', sort_order: 61 },
  { id: 'dc-gcse-revision-0062', deck_id: 'deck-gcse-revision', front: 'How do you rearrange a formula to change the subject?', back: 'Apply inverse operations to isolate the desired variable, treating it like solving an equation.\n\nExample: v = u + at → rearrange for t:\n  v − u = at\n  t = (v − u)/a\n\nHarder: v² = u² + 2as, rearrange for u:\n  u² = v² − 2as\n  u = √(v² − 2as)\n\nGCSE Tip: If the new subject appears more than once, collect the terms on one side and factorise.', sort_order: 62 },
  { id: 'dc-gcse-revision-0063', deck_id: 'deck-gcse-revision', front: 'What is the difference between an expression, equation, formula, and identity?', back: 'Expression: no equals sign. E.g. 3x² + 2x\nEquation: equals sign, solve for variable. E.g. 3x + 1 = 10\nFormula: relates two or more variables. E.g. A = πr²\nIdentity: true for ALL values, shown with ≡. E.g. (x+1)² ≡ x² + 2x + 1\n\nGCSE Tip: If asked to "show an identity", expand/simplify one side until it equals the other — do not move terms across the ≡.', sort_order: 63 },
  { id: 'dc-gcse-revision-0064', deck_id: 'deck-gcse-revision', front: 'How do you simplify algebraic fractions?', back: 'Factorise the numerator and denominator, then cancel common factors.\n\nExample:\n  (x² − 4) / (x² − x − 2)\n  = (x+2)(x−2) / (x−2)(x+1)\n  = (x+2) / (x+1) [provided x ≠ 2]\n\nGCSE Tip: Never "cancel" individual terms — only cancel common FACTORS. Always factorise first.', sort_order: 64 },
  { id: 'dc-gcse-revision-0065', deck_id: 'deck-gcse-revision', front: 'How do you add and subtract algebraic fractions?', back: 'Find a common denominator (usually the product of the denominators), rewrite each fraction, then add/subtract numerators.\n\nExample:\n  3/(x+1) + 2/(x−2)\n  = [3(x−2) + 2(x+1)] / [(x+1)(x−2)]\n  = (3x − 6 + 2x + 2) / [(x+1)(x−2)]\n  = (5x − 4) / [(x+1)(x−2)]\n\nGCSE Tip: Expand the numerator fully, collect like terms, but leave the denominator factorised.', sort_order: 65 },
  { id: 'dc-gcse-revision-0066', deck_id: 'deck-gcse-revision', front: 'How do you sketch a quadratic graph (parabola)?', back: 'Key features to identify:\n  1. Roots: solve f(x) = 0 (x-intercepts)\n  2. y-intercept: substitute x = 0\n  3. Vertex: x = −b/2a; substitute to get y\n  4. Direction: a > 0 → U-shape; a < 0 → ∩-shape\n\nLabel all key points.\n\nGCSE Tip: The parabola is symmetric about x = −b/2a. Midpoint of the roots = vertex x-coordinate.', sort_order: 66 },
  { id: 'dc-gcse-revision-0067', deck_id: 'deck-gcse-revision', front: 'How do you identify the graph of y = x³, y = 1/x, and y = kˣ?', back: 'y = x³: S-shaped cubic, passes through origin, goes up-right and down-left.\ny = 1/x: rectangular hyperbola, two branches (1st and 3rd quadrant), never touches axes.\ny = kˣ (k>1): exponential growth, passes through (0,1), always positive, increases rapidly.\n\nGCSE Tip: Learn to recognise these shapes from their graph or equation. Translations and reflections shift them but preserve the basic shape.', sort_order: 67 },
  { id: 'dc-gcse-revision-0068', deck_id: 'deck-gcse-revision', front: 'What are the graph transformations f(x+a), f(x)+a, f(ax), and af(x)?', back: 'f(x) + a → translate UP by a\nf(x) − a → translate DOWN by a\nf(x + a) → translate LEFT by a\nf(x − a) → translate RIGHT by a\naf(x) → stretch vertically by factor a\nf(ax) → stretch horizontally by factor 1/a\n−f(x) → reflect in x-axis\nf(−x) → reflect in y-axis\n\nGCSE Tip: "Inside" the function affects x (and works counter-intuitively). "Outside" affects y directly.', sort_order: 68 },
  { id: 'dc-gcse-revision-0069', deck_id: 'deck-gcse-revision', front: 'How do you find function values and composite functions?', back: 'f(x) = 2x + 1: f(3) = 2(3)+1 = 7\n\nComposite function fg(x): apply g first, then f.\n  If f(x) = 2x+1 and g(x) = x²:\n  fg(x) = f(g(x)) = f(x²) = 2x²+1\n  gf(x) = g(f(x)) = g(2x+1) = (2x+1)²\n\nGCSE Tip: fg ≠ gf in general. Always apply the RIGHTMOST function first.', sort_order: 69 },
  { id: 'dc-gcse-revision-0070', deck_id: 'deck-gcse-revision', front: 'How do you find the inverse function f⁻¹(x)?', back: 'Replace f(x) with y, swap x and y, solve for y, replace y with f⁻¹(x).\n\nExample: f(x) = 3x − 5\n  y = 3x − 5 → x = 3y − 5 → y = (x+5)/3\n  f⁻¹(x) = (x+5)/3\n\nNote: f(f⁻¹(x)) = x for all x in the domain.\n\nGCSE Tip: The graph of f⁻¹ is the reflection of f in the line y = x.', sort_order: 70 },
  { id: 'dc-gcse-revision-0071', deck_id: 'deck-gcse-revision', front: 'How do you solve equations graphically?', back: 'To solve f(x) = g(x): plot both graphs on the same axes. The x-coordinates of the intersection points are the solutions.\n\nExample: Solve x² = x + 2 graphically:\n  Plot y = x² and y = x + 2. Intersections at x = −1 and x = 2.\n\nTo use an existing graph of y = f(x): draw the appropriate straight line y = k or y = mx + c to match the equation.\n\nGCSE Tip: Read intersections as accurately as possible from the graph. State the x-values clearly.', sort_order: 71 },
  { id: 'dc-gcse-revision-0072', deck_id: 'deck-gcse-revision', front: 'What is the equation of a circle centred at the origin?', back: 'x² + y² = r², where r is the radius.\n\nExample: x² + y² = 25 → circle centred at (0,0) with radius 5.\n\nPoints on the circle satisfy the equation: (3,4) → 9+16=25 ✓\n\nGCSE Tip: For a tangent to the circle at point (a,b): the tangent is perpendicular to the radius at that point. Radius gradient = b/a; tangent gradient = −a/b.', sort_order: 72 },
  { id: 'dc-gcse-revision-0073', deck_id: 'deck-gcse-revision', front: 'How do you draw and interpret distance-time graphs?', back: 'Gradient = speed (steeper = faster).\nHorizontal line = stationary.\nNegative gradient = returning towards the start.\n\nAverage speed = total distance / total time\n\nExample: 0→3 min: travelled 120 m; 3→5 min: stationary; 5→8 min: returned to 0.\n  Speed outward = 120/3 = 40 m/min\n\nGCSE Tip: Speed is always positive — use magnitude of gradient even for the return journey.', sort_order: 73 },
  { id: 'dc-gcse-revision-0074', deck_id: 'deck-gcse-revision', front: 'How do you draw and interpret velocity-time graphs?', back: 'Gradient = acceleration (positive gradient = acceleration, negative = deceleration).\nArea under graph = distance travelled.\n\nFor triangles: area = ½ × base × height\nFor trapeziums: area = ½(a+b)×h\n\nGCSE Tip: Always use the correct formula for the shape of each section of the graph. Units for area will be (unit of v) × (unit of t) = unit of distance.', sort_order: 74 },
  { id: 'dc-gcse-revision-0075', deck_id: 'deck-gcse-revision', front: 'What are the properties of a linear sequence with nth term T(n) = dn + c?', back: 'The common difference d is the coefficient of n.\nThe term before the first (T(0)) = c = T(1) − d.\n\nExample: T(n) = 4n − 1\n  d = 4 (each term increases by 4)\n  T(1) = 3, T(2) = 7, T(3) = 11…\n  c = −1 (not a term in the sequence but useful for the formula)\n\nGCSE Tip: If asked "is 100 in this sequence?", set 4n − 1 = 100 → n = 25.25 → not a whole number → 100 is NOT in the sequence.', sort_order: 75 },
  { id: 'dc-gcse-revision-0076', deck_id: 'deck-gcse-revision', front: 'How do you find the nth term of a quadratic sequence?', back: 'Find first and second differences:\n  Sequence: 3, 8, 15, 24, 35…\n  1st differences: 5, 7, 9, 11 (not constant)\n  2nd differences: 2, 2, 2 (constant = 2)\n  a = 2nd diff / 2 = 1 → starts with n²\n\n  Compare n²: 1, 4, 9, 16, 25 vs 3, 8, 15, 24, 35 → diff = 2, 4, 6, 8, 10 = 2n\n  nth term = n² + 2n\n\nGCSE Tip: If 2nd difference = 2a, coefficient of n² is a.', sort_order: 76 },
  { id: 'dc-gcse-revision-0077', deck_id: 'deck-gcse-revision', front: 'How do you solve equations involving fractions?', back: 'Multiply every term by the LCM of the denominators to eliminate fractions.\n\nExample: x/3 + x/4 = 7\n  Multiply by 12: 4x + 3x = 84 → 7x = 84 → x = 12\n\nHarder: 3/(x+1) = 2/(x−2)\n  Cross multiply: 3(x−2) = 2(x+1) → 3x−6 = 2x+2 → x = 8\n\nGCSE Tip: After solving, check the solution does not make any denominator = 0.', sort_order: 77 },
  { id: 'dc-gcse-revision-0078', deck_id: 'deck-gcse-revision', front: 'What is a function and what is meant by domain and range?', back: 'Function: a rule that maps each input (x) to exactly one output f(x).\nDomain: the set of allowed input values.\nRange: the set of corresponding output values.\n\nExample: f(x) = 1/x has domain x ≠ 0; range = all real numbers except 0.\nf(x) = √x has domain x ≥ 0; range = f(x) ≥ 0.\n\nGCSE Tip: State the domain restriction whenever you see division by x or square roots of x.', sort_order: 78 },
  { id: 'dc-gcse-revision-0079', deck_id: 'deck-gcse-revision', front: 'How do you solve quadratic inequalities?', back: 'Method:\n1. Solve the related quadratic equation (= 0) to find the critical values.\n2. Sketch the parabola to identify regions.\n3. Determine where the inequality is satisfied.\n\nExample: x² − 5x + 6 < 0\n  (x−2)(x−3) = 0 → x = 2 or x = 3\n  Parabola opens upward → below zero BETWEEN roots.\n  Solution: 2 < x < 3\n\nGCSE Tip: "Between roots" for < 0 (U-shape); "outside roots" for > 0.', sort_order: 79 },
  { id: 'dc-gcse-revision-0080', deck_id: 'deck-gcse-revision', front: 'How do you plot and interpret a graph of y = ax² + bx + c?', back: 'Steps:\n1. Make a table of values: substitute x = …, −2, −1, 0, 1, 2, …\n2. Plot points and join with a smooth curve.\n3. Label roots (where y=0), y-intercept (x=0), and vertex.\n\nThe y-intercept is always c.\nVertex x-coordinate: x = −b/2a.\n\nGCSE Tip: Use a ruler and pencil for plotting. A smooth continuous curve scores better than a zig-zag.', sort_order: 80 },
  { id: 'dc-gcse-revision-0081', deck_id: 'deck-gcse-revision', front: 'What is algebraic proof and how do you write one?', back: 'To prove a statement algebraically:\n1. Express numbers/relationships using algebra (e.g. even = 2n, odd = 2n+1, consecutive = n and n+1).\n2. Manipulate the algebra to reach the required conclusion.\n3. End with a clear concluding statement.\n\nExample: Prove sum of two odd numbers is even.\n  (2m+1)+(2n+1) = 2m+2n+2 = 2(m+n+1) → even.\n\nGCSE Tip: Never use specific numbers in a proof — use general algebraic forms.', sort_order: 81 },
  { id: 'dc-gcse-revision-0082', deck_id: 'deck-gcse-revision', front: 'How do you solve equations using iteration?', back: 'Rearrange the equation to the form x = g(x), then use: xₙ₊₁ = g(xₙ) starting from an initial estimate x₀.\n\nExample: x³ + x = 4, rearranged as x = (4−x)^(1/3)… or x = ∛(4−x).\n  x₀ = 1: x₁ = ∛3 ≈ 1.442; x₂ = ∛(4−1.442) ≈ 1.366; continues to converge.\n\nGCSE Tip: Carry at least 4 d.p. throughout. Show at least 3 iterations. Check convergence.', sort_order: 82 },
  { id: 'dc-gcse-revision-0083', deck_id: 'deck-gcse-revision', front: 'What does the gradient of a curve represent and how do you estimate it?', back: 'The gradient of a curve at a point equals the instantaneous rate of change there.\n\nTo estimate: draw a tangent at the point (a straight line just touching the curve) and calculate its gradient using two points on the tangent.\n\nGradient = rise/run = (y₂−y₁)/(x₂−x₁)\n\nGCSE Tip: Choose two points far apart on the tangent for accuracy. The tangent should touch — not cross — the curve at that point.', sort_order: 83 },
  { id: 'dc-gcse-revision-0084', deck_id: 'deck-gcse-revision', front: 'How do you estimate the area under a curve (trapezium rule)?', back: 'Divide the area into vertical strips of equal width h, read y-values at each vertical boundary, then apply:\n  Area ≈ h/2 × [y₀ + 2(y₁ + y₂ + … + yₙ₋₁) + yₙ]\n\nwhere y₀ and yₙ are the two end values.\n\nAlternatively: count squares under the curve on a grid.\n\nGCSE Tip: The more strips, the more accurate. State whether your estimate is an over- or under-estimate depending on whether the curve is concave up or down.', sort_order: 84 },
  { id: 'dc-gcse-revision-0085', deck_id: 'deck-gcse-revision', front: 'How do you set up and solve equations from word problems?', back: 'Steps:\n1. Define a variable (e.g. "let x = the unknown").\n2. Translate the word problem into an equation.\n3. Solve the equation.\n4. Interpret the answer in context.\n\nExample: "A number is 5 more than twice another. Together they total 23."\n  Let x = first number. Second = 2x+5.\n  x + (2x+5) = 23 → 3x = 18 → x = 6, other = 17.\n\nGCSE Tip: Check: 6+17=23 ✓ and 17 = 2×6+5 ✓.', sort_order: 85 },
  { id: 'dc-gcse-revision-0086', deck_id: 'deck-gcse-revision', front: 'What is the difference between a term, coefficient, and constant in an expression?', back: 'Term: a single number, variable, or product. In 3x² − 5x + 7, the terms are 3x², −5x, 7.\nCoefficient: the numerical multiplier of a variable. Coefficient of x² is 3; of x is −5.\nConstant: a term with no variable. Here, the constant is 7.\n\nGCSE Tip: In GCSE questions on "write an expression", ensure you correctly identify what is given (constant) and what varies.', sort_order: 86 },
  { id: 'dc-gcse-revision-0087', deck_id: 'deck-gcse-revision', front: 'How do you use trial and improvement to solve equations?', back: 'Choose an initial estimate, evaluate f(x), narrow down the interval, repeat.\n\nExample: x³ + x = 25, find to 1 d.p.\n  x=2: 8+2=10 (too low); x=3: 27+3=30 (too high); x=2.5: 15.6+2.5=18.1 (low);\n  x=2.8: 21.95+2.8=24.75 (low); x=2.9: 24.39+2.9=27.29 (high)\n  → between 2.8 and 2.9; try 2.85 → 26.0 (high) → x ≈ 2.8\n\nGCSE Tip: Show a table. Always check the "half" value to determine which side to round to.', sort_order: 87 },
  { id: 'dc-gcse-revision-0088', deck_id: 'deck-gcse-revision', front: 'How do you interpret and solve inequalities on a graph?', back: 'For y > mx + c: shade above the line (dashed line — boundary not included).\nFor y ≤ mx + c: shade below or on the line (solid line — boundary included).\n\nFor a region satisfying multiple inequalities: shade the overlap (or unshaded region depending on convention).\n\nGCSE Tip: Read the question carefully — mark the REQUIRED region (sometimes asked to leave unshaded). Test a point like (0,0) to confirm which side satisfies the inequality.', sort_order: 88 },
  { id: 'dc-gcse-revision-0089', deck_id: 'deck-gcse-revision', front: 'How do you use a straight-line graph to solve an equation?', back: 'If you have a plotted curve y = f(x) and need to solve f(x) = k:\n  Draw the horizontal line y = k. The x-coordinates where this intersects the curve are the solutions.\n\nIf you need to solve f(x) = mx + c:\n  Draw the line y = mx + c and find intersections with y = f(x).\n\nExample: Using y = x² − 3x, solve x² − 3x = 2: draw y = 2 on the same graph.\n\nGCSE Tip: The question usually says "on your graph draw a suitable straight line" — the skill is constructing the right line.', sort_order: 89 },
  { id: 'dc-gcse-revision-0090', deck_id: 'deck-gcse-revision', front: 'What is direct proportion and how is it shown on a graph?', back: 'y ∝ x means y = kx (k is the constant of proportionality).\n\nGraph: a straight line through the ORIGIN with gradient k.\n\nExample: If y=15 when x=3, then k = 15/3 = 5 → y = 5x.\n\nOther types: y ∝ x² (y = kx²) — parabola through origin; y ∝ √x (y = k√x).\n\nGCSE Tip: "Directly proportional" always means the graph passes through the origin.', sort_order: 90 },
  { id: 'dc-gcse-revision-0091', deck_id: 'deck-gcse-revision', front: 'How do you solve problems involving inverse proportion?', back: 'y ∝ 1/x means y = k/x, so xy = k (constant).\n\nExample: y = 6 when x = 4 → k = 24 → y = 24/x.\n  When x = 8: y = 24/8 = 3.\n\nGraph: hyperbola (never touches axes).\n\nOther types: y ∝ 1/x² means y = k/x².\n\nGCSE Tip: If y halves when x doubles, that is inverse proportion. Find k first — then all other pairs.', sort_order: 91 },
  { id: 'dc-gcse-revision-0092', deck_id: 'deck-gcse-revision', front: 'What is the factor theorem and how do you use it to factorise a cubic?', back: 'Factor theorem: (x − a) is a factor of f(x) if and only if f(a) = 0.\n\nExample: Factorise f(x) = x³ − 6x² + 11x − 6.\n  Try f(1) = 1−6+11−6 = 0 → (x−1) is a factor.\n  Divide: f(x) = (x−1)(x²−5x+6) = (x−1)(x−2)(x−3).\n\nGCSE Tip: Test small integers ±1, ±2, ±3 first. Polynomial long division or comparing coefficients completes the factorisation.', sort_order: 92 },
  { id: 'dc-gcse-revision-0093', deck_id: 'deck-gcse-revision', front: 'How do you sketch the graph of y = sin(x) and y = cos(x)?', back: 'y = sin(x):\n  Period 360°. Amplitude 1. Passes through (0,0), max 1 at 90°, 0 at 180°, min −1 at 270°.\n\ny = cos(x):\n  Period 360°. Amplitude 1. Starts at (0,1), zero at 90°, −1 at 180°, zero at 270°, back to 1 at 360°.\n\ncos(x) = sin(x+90°) — cosine is a 90° shift of sine.\n\nGCSE Tip: Learn the five key points for each curve. Transformations of these graphs appear in Higher-tier papers.', sort_order: 93 },
  { id: 'dc-gcse-revision-0094', deck_id: 'deck-gcse-revision', front: 'How do you sketch y = tan(x)?', back: 'y = tan(x):\n  Period 180°. Passes through (0,0).\n  Vertical asymptotes at x = 90°, 270°, −90°… (where cos = 0).\n  tan(45°) = 1; tan(135°) = −1.\n  No maximum or minimum.\n\nGCSE Tip: The tangent graph has a different shape to sin/cos — it is not a wave. Remember the asymptotes and the period of 180° (not 360°).', sort_order: 94 },
  { id: 'dc-gcse-revision-0095', deck_id: 'deck-gcse-revision', front: 'How do you use and interpret real-life graphs (e.g. conversion, cooling)?', back: 'Read values by tracing from one axis to the graph and across to the other axis.\n\nConversion graph: straight line through (0,0) or with an intercept.\nCooling curve: exponential decay shape.\n\nGradient = rate of change (e.g. °C per minute, or km per hour).\n\nGCSE Tip: Always include units in your answer. For a steeper gradient, the rate is greater.', sort_order: 95 },

  // ── RATIO, PROPORTION & RATES OF CHANGE (cards 96–120) ──────────────────
  { id: 'dc-gcse-revision-0096', deck_id: 'deck-gcse-revision', front: 'How do you simplify a ratio involving different units?', back: 'Convert both quantities to the same unit first, then simplify by dividing by the HCF.\n\nExample: 1.5 m : 60 cm → 150 cm : 60 cm → 5 : 2\n\nExample: 45 minutes : 1.5 hours → 45 : 90 → 1 : 2\n\nGCSE Tip: Never mix units in a ratio. Always convert to the smaller unit to avoid decimals.', sort_order: 96 },
  { id: 'dc-gcse-revision-0097', deck_id: 'deck-gcse-revision', front: 'How do you solve ratio problems involving a total amount?', back: 'Step 1: add the ratio parts to find the total parts.\nStep 2: divide the total by the number of parts (= 1 part value).\nStep 3: multiply each ratio by 1 part value.\n\nExample: Share £240 in ratio 3:5:7 (total parts = 15).\n  1 part = £16; shares = £48, £80, £112.\n\nGCSE Tip: Check: 48+80+112 = 240 ✓. Always add parts before dividing.', sort_order: 97 },
  { id: 'dc-gcse-revision-0098', deck_id: 'deck-gcse-revision', front: 'How do you find a missing quantity when given a ratio and one part?', back: 'If you know the value of one part, work out the other parts directly.\n\nExample: Ratio of red:blue = 3:5. There are 12 red pens. How many blue?\n  1 part = 12/3 = 4; blue = 5 × 4 = 20.\n\nAlternatively: set up proportion.\n  red/blue = 3/5 → 12/blue = 3/5 → blue = 20.\n\nGCSE Tip: Identify which part is "known" and scale accordingly.', sort_order: 98 },
  { id: 'dc-gcse-revision-0099', deck_id: 'deck-gcse-revision', front: 'What is map scale and how do you use it?', back: 'A scale of 1:n means 1 cm on the map = n cm in reality.\n\nConvert map distance to real distance: multiply by n.\nConvert real distance to map distance: divide by n.\n\nExample: Scale 1:50 000. Map distance = 4 cm.\n  Real = 4 × 50 000 = 200 000 cm = 2 km.\n\nGCSE Tip: Convert to sensible units at the end (cm → m → km). Always state the units clearly.', sort_order: 99 },
  { id: 'dc-gcse-revision-0100', deck_id: 'deck-gcse-revision', front: 'How do you work out percentage increase and decrease?', back: 'Increase: new amount = original × (1 + r/100) = original × multiplier\n  10% increase: × 1.10\n\nDecrease: new amount = original × (1 − r/100)\n  15% decrease: × 0.85\n\nExample: £320 increased by 12% = 320 × 1.12 = £358.40\n\nGCSE Tip: Use the multiplier method — it is one step and avoids errors. 1.05 = 5% increase; 0.95 = 5% decrease.', sort_order: 100 },
  { id: 'dc-gcse-revision-0101', deck_id: 'deck-gcse-revision', front: 'How do you calculate repeated percentage change?', back: 'Apply the multiplier once for each period, OR raise to the power of the number of periods.\n\nFormula: Final = Original × (multiplier)ⁿ\n\nExample: Population of 40 000 decreases by 3% each year for 5 years:\n  Final = 40 000 × (0.97)⁵ ≈ 40 000 × 0.8587 ≈ 34 349\n\nGCSE Tip: This is exactly the compound interest formula. Memorise: A = P(1 ± r/100)ⁿ.', sort_order: 101 },
  { id: 'dc-gcse-revision-0102', deck_id: 'deck-gcse-revision', front: 'How do you find the original amount after a percentage change?', back: 'Divide by the multiplier used.\n\nExample: After a 20% increase, a price is £180. Original?\n  Multiplier = 1.20 → original = 180 ÷ 1.20 = £150\n\nExample: After a 35% decrease, value is £520. Original?\n  Multiplier = 0.65 → original = 520 ÷ 0.65 = £800\n\nGCSE Tip: Never just take the percentage off the final value — always divide by the multiplier.', sort_order: 102 },
  { id: 'dc-gcse-revision-0103', deck_id: 'deck-gcse-revision', front: 'What is a unit rate and how do you use it for comparison?', back: 'A unit rate expresses the ratio per single unit (e.g. price per item, km per hour).\n\nBest-buy comparison: calculate price per gram (or per item) for each option.\n\nExample: Pack A: 500g for £2.40 → 0.48p/g; Pack B: 750g for £3.45 → 0.46p/g → Pack B is better value.\n\nGCSE Tip: Express as pence per gram or grams per penny — both work as long as you compare the SAME unit.', sort_order: 103 },
  { id: 'dc-gcse-revision-0104', deck_id: 'deck-gcse-revision', front: 'How do you calculate average speed for a multi-stage journey?', back: 'Average speed = total distance / total time\n(NOT the mean of the individual speeds)\n\nExample:\n  Stage 1: 120 km at 60 km/h → time = 2 h\n  Stage 2: 80 km at 40 km/h → time = 2 h\n  Total = 200 km in 4 h → average speed = 50 km/h\n\nGCSE Tip: The average of 60 and 40 is 50 here — but only because the times happen to be equal. Always use the formula.', sort_order: 104 },
  { id: 'dc-gcse-revision-0105', deck_id: 'deck-gcse-revision', front: 'How do you solve currency conversion problems?', back: 'Use the given exchange rate to multiply or divide.\n\nExample: £1 = €1.15.\n  £240 → euros: 240 × 1.15 = €276\n  €345 → pounds: 345 ÷ 1.15 = £300\n\nGCSE Tip: Decide whether to × or ÷ by asking: "should the answer be bigger or smaller?" Euros > pounds, so multiplying by 1.15 gives a larger number.', sort_order: 105 },
  { id: 'dc-gcse-revision-0106', deck_id: 'deck-gcse-revision', front: 'How do you solve proportion problems using the formula y = kxⁿ?', back: 'Step 1: Identify the type of proportion (x, x², √x, etc.).\nStep 2: Use a known pair (x, y) to find k.\nStep 3: Use the formula for other values.\n\nExample: y ∝ x³. When x=2, y=24.\n  24 = k(2³) = 8k → k = 3 → y = 3x³\n  When x=4: y = 3×64 = 192\n\nGCSE Tip: The phrase "y is directly proportional to x²" → y = kx². Write the formula, find k, then use it.', sort_order: 106 },
  { id: 'dc-gcse-revision-0107', deck_id: 'deck-gcse-revision', front: 'How do you interpret a graph showing proportion?', back: 'Direct proportion (y ∝ x): straight line through origin.\nDirect proportion (y ∝ x²): parabola through origin.\nInverse proportion (y ∝ 1/x): hyperbola (product xy = constant).\n\nGCSE Tip: If the graph is a straight line through the origin → directly proportional. If it curves → it could be y ∝ x² or y ∝ 1/x. Check if xy is constant to identify inverse proportion.', sort_order: 107 },
  { id: 'dc-gcse-revision-0108', deck_id: 'deck-gcse-revision', front: 'What is growth and decay in proportion problems?', back: 'Growth: increases by a percentage each period → A = P(1 + r/100)ⁿ\nDecay: decreases by a percentage each period → A = P(1 − r/100)ⁿ\n\nExamples:\n  Bacteria growing at 20%/hr: 500 × (1.2)⁴ ≈ 1036\n  Car depreciating at 15%/yr: £18000 × (0.85)³ ≈ £11,006\n\nGCSE Tip: Always identify whether it is growth (+) or decay (−) before choosing the multiplier.', sort_order: 108 },
  { id: 'dc-gcse-revision-0109', deck_id: 'deck-gcse-revision', front: 'How do you solve time problems (hours, minutes, and seconds)?', back: 'Convert time carefully:\n  1 hour = 60 minutes; 1 minute = 60 seconds.\n  To convert hours to a decimal: divide minutes by 60.\n  E.g. 2 h 45 min = 2 + 45/60 = 2.75 hours.\n\nTo convert back: 0.75 × 60 = 45 min.\n\nGCSE Tip: Never multiply minutes by 0.1 — always divide by 60 to convert to hours. This is a very common error.', sort_order: 109 },
  { id: 'dc-gcse-revision-0110', deck_id: 'deck-gcse-revision', front: 'How do you work with pressure?', back: 'Pressure = Force ÷ Area\nForce = Pressure × Area\nArea = Force ÷ Pressure\n\nUnits: Pa (pascals) = N/m²; or N/cm²\n\nExample: Force = 60 N, Area = 0.3 m² → Pressure = 60/0.3 = 200 Pa\n\nGCSE Tip: Convert area to correct units first. 1 m² = 10 000 cm². Use the same triangle approach as speed and density.', sort_order: 110 },
  { id: 'dc-gcse-revision-0111', deck_id: 'deck-gcse-revision', front: 'How do you interpret gradient on a graph in context?', back: 'Gradient = rate of change of y with respect to x.\n\n• Distance-time graph → gradient = speed\n• Velocity-time graph → gradient = acceleration\n• Cost-number graph → gradient = cost per item\n• Temperature-time → gradient = rate of cooling (°C per minute)\n\nGCSE Tip: Always attach UNITS to the gradient. Calculate it carefully: rise ÷ run = (change in y) ÷ (change in x).', sort_order: 111 },
  { id: 'dc-gcse-revision-0112', deck_id: 'deck-gcse-revision', front: 'What is a conversion graph and how do you use it?', back: 'A conversion graph is a straight-line graph used to convert between two units or scales (e.g. £ to €, miles to km, °C to °F).\n\nTo use:\n  • Find your starting value on one axis.\n  • Draw a horizontal line to the graph, then vertically to the other axis.\n  • Read off the converted value.\n\nGCSE Tip: Check whether the line passes through the origin (direct proportion) or not (e.g. °C to °F has an intercept).', sort_order: 112 },
  { id: 'dc-gcse-revision-0113', deck_id: 'deck-gcse-revision', front: 'How do you solve proportion problems involving recipes or mixtures?', back: 'Scale all quantities up or down by the same factor.\n\nExample: A recipe for 4 people needs 200 g flour and 3 eggs. For 10 people:\n  Scale factor = 10/4 = 2.5\n  Flour: 200 × 2.5 = 500 g; Eggs: 3 × 2.5 = 7.5 → round to 8 eggs.\n\nGCSE Tip: Show the scale factor clearly. In a practical context, always round UP for ingredients.', sort_order: 113 },
  { id: 'dc-gcse-revision-0114', deck_id: 'deck-gcse-revision', front: 'What is a percentage point change vs a percentage change?', back: 'Percentage point change: the arithmetic difference between two percentages.\n  E.g. Interest rate rises from 2% to 5% → +3 percentage points.\n\nPercentage change: the relative change as a percentage of the original.\n  E.g. 2% → 5% → % change = (3/2)×100 = 150% increase.\n\nGCSE Tip: GCSE usually asks for % change, not percentage points. Watch the phrasing carefully.', sort_order: 114 },
  { id: 'dc-gcse-revision-0115', deck_id: 'deck-gcse-revision', front: 'How do you find the gradient of a straight line from its equation?', back: 'Rearrange to the form y = mx + c. The gradient is m.\n\nExample: 3x + 2y = 10\n  2y = −3x + 10 → y = −(3/2)x + 5\n  Gradient = −3/2\n\nGCSE Tip: If the coefficient of y is negative after rearranging, divide carefully. The gradient of a horizontal line (y = k) is 0. A vertical line (x = k) has undefined gradient.', sort_order: 115 },
  { id: 'dc-gcse-revision-0116', deck_id: 'deck-gcse-revision', front: 'How do you use proportion to solve problems about workers or machines?', back: 'If more workers/machines → less time (inverse proportion).\n\nExample: 4 workers complete a job in 6 days.\n  Total work = 4 × 6 = 24 worker-days.\n  For 3 workers: 24 ÷ 3 = 8 days.\n\nGCSE Tip: Multiply to find total work units first, then divide by the new number. This assumes each worker works at the same rate.', sort_order: 116 },
  { id: 'dc-gcse-revision-0117', deck_id: 'deck-gcse-revision', front: 'How do you calculate rates involving compound units (e.g. m/s, kg/m³)?', back: 'Compound unit: formed from two base units using × or ÷.\n  Speed: m/s; Density: kg/m³; Pressure: N/m²; Flow rate: litres/min.\n\nAlways use the triangle:\n  D = S × T → S = D/T → T = D/S\n\nGCSE Tip: Ensure units of inputs match the unit of the formula. Convert if needed (e.g. cm³ to m³ by ÷1 000 000).', sort_order: 117 },
  { id: 'dc-gcse-revision-0118', deck_id: 'deck-gcse-revision', front: 'How do you calculate VAT and interpret price-inclusive problems?', back: 'VAT (currently 20%): price including VAT = original × 1.20\nTo find price before VAT: price ÷ 1.20\n\nExample: A laptop costs £780 including 20% VAT.\n  Pre-VAT price = 780 ÷ 1.20 = £650\n  VAT amount = £780 − £650 = £130\n\nGCSE Tip: Students often make the mistake of finding 20% of £780. Always divide by the multiplier.', sort_order: 118 },
  { id: 'dc-gcse-revision-0119', deck_id: 'deck-gcse-revision', front: 'How do you solve problems involving population density?', back: 'Population density = population ÷ area\n  (people per km² or per m²)\n\nExample: A town has population 45 000 over an area of 90 km².\n  Density = 45 000 ÷ 90 = 500 people/km²\n\nFor area: area = population ÷ density\n\nGCSE Tip: Same structure as density = mass/volume. Identify the "numerator quantity" (population/mass) and "denominator quantity" (area/volume).', sort_order: 119 },
  { id: 'dc-gcse-revision-0120', deck_id: 'deck-gcse-revision', front: 'How do you use a multiplier for a series of percentage changes?', back: 'Multiply the individual multipliers together.\n\nExample: A price increases by 10%, then decreases by 5%.\n  Combined multiplier = 1.10 × 0.95 = 1.045\n  Net result: a 4.5% increase (NOT 5%)\n\nGCSE Tip: You cannot simply add/subtract percentages. Always multiply the multipliers. Order does not matter for the final result (multiplication is commutative).', sort_order: 120 },

  // ── GEOMETRY & MEASURES — Part 1 (cards 121–150) ────────────────────────
  { id: 'dc-gcse-revision-0121', deck_id: 'deck-gcse-revision', front: 'What are the angle facts at a point, on a straight line, and in a triangle?', back: 'Angles at a point: sum = 360°\nAngles on a straight line: sum = 180°\nAngles in a triangle: sum = 180°\nAngles in a quadrilateral: sum = 360°\n\nExterior angle of a triangle = sum of the two non-adjacent interior angles.\n\nGCSE Tip: Always state the angle fact/rule as the reason in geometry proofs ("angles on a straight line sum to 180°").', sort_order: 121 },
  { id: 'dc-gcse-revision-0122', deck_id: 'deck-gcse-revision', front: 'What are the angle properties of parallel lines?', back: 'Alternate angles (Z-angles): equal. They are between the parallel lines, on opposite sides of the transversal.\n\nCorresponding angles (F-angles): equal. On the same side of the transversal.\n\nCo-interior (same-side/allied) angles (C-angles): add up to 180°.\n\nGCSE Tip: Name the angle type and the lines when giving a reason: "alternate angles, AB ∥ CD".', sort_order: 122 },
  { id: 'dc-gcse-revision-0123', deck_id: 'deck-gcse-revision', front: 'What are the properties of special quadrilaterals?', back: 'Square: all sides equal, all angles 90°, 4 lines of symmetry, order-4 rotational.\nRectangle: opposite sides equal, all 90°, 2 lines of symmetry.\nRhombus: all sides equal, opposite angles equal, 2 lines of symmetry, diagonals bisect at 90°.\nParallelogram: opposite sides ∥ and equal, no lines of symmetry.\nTrapezium: one pair of parallel sides.\nKite: two pairs of adjacent equal sides, one line of symmetry, diagonals cross at 90°.\n\nGCSE Tip: Learn the diagonals too — they often appear in Pythagoras questions.', sort_order: 123 },
  { id: 'dc-gcse-revision-0124', deck_id: 'deck-gcse-revision', front: 'What is the interior and exterior angle of a regular polygon?', back: 'Sum of interior angles of an n-gon = (n − 2) × 180°\nInterior angle of regular n-gon = (n−2)×180° / n\nExterior angle of regular n-gon = 360° / n\n\nInterior + exterior = 180° (they are supplementary).\n\nExample: Regular hexagon (n=6): exterior = 60°; interior = 120°\n\nGCSE Tip: If given an interior angle, find n using: n = 360/(180 − interior).', sort_order: 124 },
  { id: 'dc-gcse-revision-0125', deck_id: 'deck-gcse-revision', front: 'How do you find the area of a triangle?', back: 'Area = ½ × base × height (perpendicular height, not slant)\n\nAlso (using trigonometry — Higher):\n  Area = ½ab sin C, where a and b are two sides and C is the included angle.\n\nExample: base = 8 cm, height = 5 cm → Area = ½ × 8 × 5 = 20 cm²\n\nGCSE Tip: The height must be perpendicular to the base. On a non-right triangle, this may need to be calculated.', sort_order: 125 },
  { id: 'dc-gcse-revision-0126', deck_id: 'deck-gcse-revision', front: 'How do you find the area of a trapezium?', back: 'Area = ½ × (a + b) × h\n  where a and b are the parallel sides and h is the perpendicular height between them.\n\nExample: a = 5 cm, b = 9 cm, h = 4 cm\n  Area = ½ × (5+9) × 4 = ½ × 14 × 4 = 28 cm²\n\nGCSE Tip: Identify the two parallel sides first. The height is always perpendicular — not a slant side.', sort_order: 126 },
  { id: 'dc-gcse-revision-0127', deck_id: 'deck-gcse-revision', front: 'How do you find the circumference and area of a circle?', back: 'Circumference = πd = 2πr\nArea = πr²\n\nExample: radius = 7 cm\n  Circumference = 2π(7) = 14π ≈ 43.98 cm\n  Area = π(7²) = 49π ≈ 153.94 cm²\n\nGCSE Tip: Leave answers in terms of π unless asked for a decimal. Diameter = 2r — check whether the question gives radius or diameter.', sort_order: 127 },
  { id: 'dc-gcse-revision-0128', deck_id: 'deck-gcse-revision', front: 'How do you find arc length and sector area?', back: 'Arc length = (θ/360) × 2πr = (θ/360) × πd\nSector area = (θ/360) × πr²\n\nwhere θ is the angle of the sector in degrees.\n\nExample: r = 6 cm, θ = 120°\n  Arc length = (120/360) × 2π(6) = (1/3) × 12π = 4π cm\n  Sector area = (120/360) × π(36) = 12π cm²\n\nGCSE Tip: Think of it as a fraction of the full circle. 120° = 1/3 of 360°.', sort_order: 128 },
  { id: 'dc-gcse-revision-0129', deck_id: 'deck-gcse-revision', front: 'How do you find the volume of a prism?', back: 'Volume of prism = Area of cross-section × length\n\nTypes:\n  Cuboid: V = l × w × h\n  Cylinder: V = πr² × h\n  Triangular prism: V = (½bh) × l\n\nExample: Triangular prism with base 4 cm, height 3 cm, length 10 cm:\n  V = ½(4)(3) × 10 = 60 cm³\n\nGCSE Tip: Identify the cross-section first (the constant shape running through the prism). Calculate its area, then multiply by the length.', sort_order: 129 },
  { id: 'dc-gcse-revision-0130', deck_id: 'deck-gcse-revision', front: 'How do you find the volume and surface area of a cylinder?', back: 'Volume = πr²h\nCurved surface area = 2πrh\nTotal surface area = 2πrh + 2πr² = 2πr(h + r)\n\nExample: r = 3 cm, h = 8 cm\n  V = π(9)(8) = 72π ≈ 226.2 cm³\n  TSA = 2π(3)(8+3) = 66π ≈ 207.3 cm²\n\nGCSE Tip: The two circular ends (top and bottom) each have area πr². Don\'t forget them when calculating total surface area.', sort_order: 130 },
  { id: 'dc-gcse-revision-0131', deck_id: 'deck-gcse-revision', front: 'How do you find the volume of a pyramid and a cone?', back: 'Pyramid: V = (1/3) × base area × height\nCone: V = (1/3)πr²h\n\nExample (cone): r = 4 cm, h = 9 cm\n  V = (1/3)π(16)(9) = 48π ≈ 150.8 cm³\n\nCurved surface area of cone = πrl (l = slant height = √(r²+h²))\nTotal surface area = πrl + πr²\n\nGCSE Tip: The (1/3) factor applies to ALL pyramids and cones. Use Pythagoras to find slant height when needed.', sort_order: 131 },
  { id: 'dc-gcse-revision-0132', deck_id: 'deck-gcse-revision', front: 'How do you find the volume and surface area of a sphere?', back: 'Volume = (4/3)πr³\nSurface area = 4πr²\n\nExample: r = 5 cm\n  V = (4/3)π(125) = 500π/3 ≈ 523.6 cm³\n  SA = 4π(25) = 100π ≈ 314.2 cm²\n\nGCSE Tip: Memorise these formulae — they are given on the formula sheet in some papers but not all. Know when to use the half-sphere (hemisphere) formulae: volume = (2/3)πr³.', sort_order: 132 },
  { id: 'dc-gcse-revision-0133', deck_id: 'deck-gcse-revision', front: 'How do you find the surface area of a cuboid?', back: 'SA = 2(lw + lh + wh)\n  where l = length, w = width, h = height.\n\nExample: 5 × 3 × 4 cm\n  SA = 2(15 + 20 + 12) = 2(47) = 94 cm²\n\nAlternative: draw the net and calculate each face separately (6 faces for a cuboid — 3 pairs of identical rectangles).\n\nGCSE Tip: List the three different face areas, double each, and sum. Nets are useful for visualising surface area.', sort_order: 133 },
  { id: 'dc-gcse-revision-0134', deck_id: 'deck-gcse-revision', front: 'How do you use Pythagoras\' theorem?', back: 'In a right-angled triangle: a² + b² = c²\n  where c is the hypotenuse (longest side, opposite the right angle).\n\nFinding hypotenuse: c = √(a² + b²)\nFinding a shorter side: a = √(c² − b²)\n\nExample: a=6, b=8 → c = √(36+64) = √100 = 10\n\nGCSE Tip: Always identify the hypotenuse first (opposite 90°). If the question doesn\'t specify a right angle, check whether one is implied.', sort_order: 134 },
  { id: 'dc-gcse-revision-0135', deck_id: 'deck-gcse-revision', front: 'How do you use Pythagoras\' theorem in 3D?', back: 'Find a diagonal in a box (cuboid):\n  First find the base diagonal: d₁ = √(l² + w²)\n  Then find the space diagonal: d = √(d₁² + h²) = √(l² + w² + h²)\n\nExample: 3 cm × 4 cm × 12 cm box:\n  d = √(9 + 16 + 144) = √169 = 13 cm\n\nGCSE Tip: Draw a 2D right triangle within the 3D diagram, labelling known and unknown sides.', sort_order: 135 },
  { id: 'dc-gcse-revision-0136', deck_id: 'deck-gcse-revision', front: 'What is a bearing and how do you measure one?', back: 'A bearing is an angle measured clockwise from North (0°/360°), given as a 3-digit number.\n\nExamples: North = 000°; East = 090°; South = 180°; West = 270°\n\nTo find a return bearing: add or subtract 180°.\n  If bearing of B from A is 065°, bearing of A from B = 065° + 180° = 245°.\n\nGCSE Tip: Always measure bearings clockwise from North. Write three digits (e.g. 040°, not 40°).', sort_order: 136 },
  { id: 'dc-gcse-revision-0137', deck_id: 'deck-gcse-revision', front: 'What are the properties of congruent and similar shapes?', back: 'Congruent: exactly the same shape and size. Corresponding sides and angles are equal.\n  Congruence conditions: SSS, SAS, ASA, AAS, RHS.\n\nSimilar: same shape, different size. Corresponding angles equal; corresponding sides in the same ratio (scale factor k).\n  Lengths scale by k; areas scale by k²; volumes scale by k³.\n\nGCSE Tip: If you know two triangles are similar, find k from one pair of corresponding sides, then apply it.', sort_order: 137 },
  { id: 'dc-gcse-revision-0138', deck_id: 'deck-gcse-revision', front: 'How do scale factors apply to area and volume?', back: 'If linear scale factor = k:\n  Area scale factor = k²\n  Volume scale factor = k³\n\nExample: Two similar cones with radii 3 cm and 6 cm. Scale factor k = 2.\n  Ratio of areas = 4:1; ratio of volumes = 8:1.\n\nGCSE Tip: This is a frequently tested Higher topic. If areas are given, take √ to find k. If volumes, take ∛.', sort_order: 138 },
  { id: 'dc-gcse-revision-0139', deck_id: 'deck-gcse-revision', front: 'What are the four geometric transformations?', back: '1. Translation: moves shape by a vector (x/y). Size and orientation unchanged.\n2. Reflection: mirror image in a given line. Same size, reversed orientation.\n3. Rotation: turns shape by an angle about a centre. Same size.\n4. Enlargement: scales shape by a scale factor from a centre of enlargement. Changes size.\n\nGCSE Tip: When describing a transformation, give ALL required information (e.g. for rotation: angle, direction, centre).', sort_order: 139 },
  { id: 'dc-gcse-revision-0140', deck_id: 'deck-gcse-revision', front: 'How do you perform and describe a translation?', back: 'A translation moves every point by the same vector.\n  Vector (a/b): move a right (negative = left), b up (negative = down).\n\nTo describe: "Translation by vector (3/−2)"\n\nGCSE Tip: Use the word "translation" and give the vector — not just "moved 3 right and 2 down". Vectors should be written as a column vector (a/b).', sort_order: 140 },
  { id: 'dc-gcse-revision-0141', deck_id: 'deck-gcse-revision', front: 'How do you perform and describe a reflection?', back: 'Reflect every point the same perpendicular distance on the other side of the mirror line.\n\nCommon mirror lines: x-axis, y-axis, y=x, y=−x, x=k, y=k.\n\nTo describe: "Reflection in the line y = x"\n\nGCSE Tip: To reflect in y=x: swap the x and y coordinates. For y=−x: negate and swap.', sort_order: 141 },
  { id: 'dc-gcse-revision-0142', deck_id: 'deck-gcse-revision', front: 'How do you perform and describe a rotation?', back: 'To rotate: use tracing paper or count squares.\n  Rotate each vertex about the centre by the given angle in the given direction.\n\nTo describe: "Rotation, 90° clockwise, centre (2, 1)"\n\nRules (rotation about origin):\n  90° CW: (x,y) → (y,−x)\n  90° CCW: (x,y) → (−y,x)\n  180°: (x,y) → (−x,−y)\n\nGCSE Tip: Always state angle, direction (CW/CCW), and centre.', sort_order: 142 },
  { id: 'dc-gcse-revision-0143', deck_id: 'deck-gcse-revision', front: 'How do you perform and describe an enlargement?', back: 'Enlarge from a centre of enlargement by a scale factor k.\n  New distance from centre = k × original distance.\n\nNegative scale factor: shape appears on the opposite side of the centre, also inverted.\n\nFractional k (0<k<1): shape gets smaller.\n\nTo describe: "Enlargement, scale factor 3, centre (1, 2)"\n\nGCSE Tip: Draw rays from the centre through each vertex. Multiply each distance by k.', sort_order: 143 },
  { id: 'dc-gcse-revision-0144', deck_id: 'deck-gcse-revision', front: 'What is a vector and how do you add, subtract, and multiply vectors?', back: 'A vector has both magnitude and direction.\n  Addition: (a/b) + (c/d) = (a+c/b+d)\n  Subtraction: (a/b) − (c/d) = (a−c/b−d)\n  Scalar multiplication: k(a/b) = (ka/kb)\n\nExample: a = (3/2), b = (−1/4)\n  a + b = (2/6); 2a = (6/4); a − b = (4/−2)\n\nGCSE Tip: Add/subtract corresponding components. Vectors must be written in column form or using i,j notation.', sort_order: 144 },
  { id: 'dc-gcse-revision-0145', deck_id: 'deck-gcse-revision', front: 'How do you find the magnitude of a vector?', back: '|a| = √(x² + y²) for a vector (x/y).\n\nExample: a = (5/12) → |a| = √(25 + 144) = √169 = 13\n\nGCSE Tip: The magnitude is the length of the vector — use Pythagoras. A unit vector has magnitude 1: û = a/|a|.', sort_order: 145 },
  { id: 'dc-gcse-revision-0146', deck_id: 'deck-gcse-revision', front: 'How do you use vectors to prove geometric properties?', back: 'Express paths in terms of known vectors, then simplify.\n\nKey facts:\n  • Equal vectors → parallel lines of equal length\n  • Vectors that are multiples of each other → parallel\n  • If AB = kAC, then A, B, C are collinear.\n\nExample: M is midpoint of AB → AM = ½ AB\n\nGCSE Tip: Always express your journey as a combination of the given vectors (a, b). Label parallel/equal vectors clearly.', sort_order: 146 },
  { id: 'dc-gcse-revision-0147', deck_id: 'deck-gcse-revision', front: 'What is the locus of a point and how do you construct one?', back: 'A locus is the set of all points satisfying a given condition.\n\nKey loci:\n  • Equidistant from two points → perpendicular bisector\n  • Equidistant from two lines → angle bisector\n  • Fixed distance from a point → circle\n  • Fixed distance from a line → parallel line (or a track with semicircular ends)\n\nGCSE Tip: Use compass and ruler for constructions. Do not erase construction arcs — marks are awarded for seeing your method.', sort_order: 147 },
  { id: 'dc-gcse-revision-0148', deck_id: 'deck-gcse-revision', front: 'How do you construct a perpendicular bisector and angle bisector?', back: 'Perpendicular bisector of AB:\n  Set compass to >½ AB. Draw arcs above and below from A and B. Join the two intersections.\n\nAngle bisector:\n  Set compass to any radius. Draw arcs on both arms. Use same radius from both intersection points; draw arcs. Join intersection to the vertex.\n\nGCSE Tip: Always show construction arcs and leave them visible. "Construct" means using compass and ruler only — not a protractor.', sort_order: 148 },
  { id: 'dc-gcse-revision-0149', deck_id: 'deck-gcse-revision', front: 'How do you find the area of compound shapes?', back: 'Break the shape into simpler shapes (rectangles, triangles, circles, trapeziums), find each area, then add or subtract as appropriate.\n\nFor a shape with a circular section removed:\n  Area = area of rectangle − area of semicircle\n\nGCSE Tip: Clearly show how you divided the shape. Label dimensions you calculate. Watch for "perimeter" vs "area" — the perimeter of a compound shape uses arc length (not area).', sort_order: 149 },
  { id: 'dc-gcse-revision-0150', deck_id: 'deck-gcse-revision', front: 'How do you convert between units of area and volume?', back: 'Area:\n  1 m² = 10 000 cm² (× 10²)²\n  1 cm² = 100 mm²\n\nVolume:\n  1 m³ = 1 000 000 cm³ (× 10³)³\n  1 cm³ = 1 000 mm³\n  1 litre = 1 000 cm³; 1 m³ = 1 000 litres\n\nGCSE Tip: Square or cube the linear conversion factor. 1 m = 100 cm → 1 m² = 100² = 10 000 cm²; 1 m³ = 100³ = 1 000 000 cm³.', sort_order: 150 },
];
